<div><div class="case-container center mt25 clearfix position-relative"><div class="left"><div class="news-box fs-14"><?php if ($list): foreach ($list as $item): ?><div class="news-list pd20 boxsh clearfix mb25 wow fadeInUp" data-wow-delay="0.1s"><div class="news-left-img fl"><a href="<?= $item['link'] ?: '/detail/news' . $item['id'] . '.html' ?>" target="<?= $item['target'] ?: '_self' ?>"><img class="lazy" data-original="<?= $item['image'] ?>" alt="<?= htmlspecialchars($item['title'], ENT_QUOTES, 'UTF-8') ?>" width="230" height="162" src="<?= $item['image'] ?>" style="display: inline;"></a></div><div class="news-right-text fr"><h3 class="ellipsis"><a href="<?= $item['link'] ?: '/detail/news' . $item['id'] . '.html' ?>" target="<?= $item['target'] ?: '_self' ?>"><?= $item['title'] ?></a></h3><p class="mt15 c888 line-h-1-7"><?= $item['sketch'] ?></p><p class="over-hidden mt20"><span class="c888 fl">更新时间：<?= date('Y-m-d H:i:s', (int) $item['create_time']) ?></span><a href="<?= $item['link'] ?: '/detail/news' . $item['id'] . '.html' ?>" target="<?= $item['target'] ?: '_self' ?>" class="danger-color fr">查看详情&gt;&gt;</a></p></div></div><?php endforeach; else: ?><i>没有更多了。。。。</i><?php endif; ?></div><?php if ($totalPage > 1): ?><?php $pageStart = (int)(floor(($page - 1) / 10) * 10) + 1; $pageEnd = min($pageStart + 9, $totalPage); ?><nav class="fenye pd20 boxsh mt25 wow fadeInUp" data-wow-delay="0.1s" aria-label="新闻分页"><ul class="pagination-list"><li<?= $page <= 1 ? ' class="disabled"' : '' ?>><?php if ($page > 1): ?><a href="?page=1">首页</a><?php else: ?><span>首页</span><?php endif; ?></li><li<?= $page <= 1 ? ' class="disabled"' : '' ?>><?php if ($page > 1): ?><a href="?page=<?= $page - 1 ?>" rel="prev">上一页</a><?php else: ?><span>上一页</span><?php endif; ?></li><?php for ($i = $pageStart; $i <= $pageEnd; $i++): ?><li<?= $i === $page ? ' class="thisclass"' : '' ?>><a href="?page=<?= $i ?>"<?= $i === $page ? ' aria-current="page"' : '' ?>><?= $i ?></a></li><?php endfor; ?><li<?= $page >= $totalPage ? ' class="disabled"' : '' ?>><?php if ($page < $totalPage): ?><a href="?page=<?= $page + 1 ?>" rel="next">下一页</a><?php else: ?><span>下一页</span><?php endif; ?></li><li<?= $page >= $totalPage ? ' class="disabled"' : '' ?>><?php if ($page < $totalPage): ?><a href="?page=<?= $totalPage ?>">末页</a><?php else: ?><span>末页</span><?php endif; ?></li><li class="page-jump"><form method="get" action=""><label for="news-page">第</label><input id="news-page" name="page" type="number" min="1" max="<?= $totalPage ?>" value="<?= $page ?>" inputmode="numeric" aria-label="跳转页码"><span>页</span><button type="submit">跳转</button></form></li></ul></nav><?php endif; ?></div><?php include VIEW_PATH . 'layout/news_right.php'; ?></div></div>
